function normalizeText(value) {
  return String(value || "")
    .toLowerCase()
    .replace(/ё/g, "е")
    .replace(/[^a-zа-я0-9]+/gi, " ")
    .trim();
}

function tokenize(value) {
  const stopWords = new Set([
    "что", "как", "или", "это", "для", "при", "без", "есть", "нет", "надо", "нужно",
    "бизнес", "компания", "команды", "команда", "клиенты", "клиентов", "очень", "много",
    "routehint", "entrymode", "free", "text", "problem", "unknown", "unclear",
    "the", "and", "for", "with", "from", "this", "that"
  ]);
  return normalizeText(value)
    .split(/\s+/)
    .filter((item) => item.length >= 4 && !stopWords.has(item));
}

function scoreText(itemText, queryTokens) {
  const normalized = normalizeText(itemText);
  return queryTokens.reduce((score, token) => {
    if (normalized.includes(token)) {
      return score + Math.min(token.length, 12);
    }
    return score;
  }, 0);
}

function compactText(value, maxLength = 260) {
  const text = String(value || "").replace(/\s+/g, " ").trim();
  if (text.length <= maxLength) {
    return softenLinearLanguage(text);
  }

  return softenLinearLanguage(`${text.slice(0, maxLength - 1).trim()}…`);
}

function softenLinearLanguage(value) {
  return String(value || "")
    .replace(/сверху вниз/gi, "через управленческую и операционную логику")
    .replace(/верхнеуровнев/gi, "системн")
    .replace(/верхним ориентиром/gi, "системным ориентиром")
    .replace(/верхняя цель/gi, "главная цель");
}

function stringifyPacket(value) {
  if (!value) {
    return "";
  }

  if (typeof value === "string") {
    return value;
  }

  try {
    return JSON.stringify(value);
  } catch {
    return "";
  }
}

function isArchitectureMetaQuestion(context) {
  const text = normalizeText(context.userText || "");
  return /сло[еяи]|структур|метод|карт|анализиру/.test(text) &&
    /скольк|каки|через|по чем|как ты|что использу/.test(text);
}

function layerNamesForIds(ids) {
  const idSet = new Set(ids.filter(Boolean));
  return BUSINESS_ARCHITECTURE_LAYERS
    .filter((layer) => idSet.has(layer.id))
    .map((layer) => layer.name);
}

function selectTop(items, query, textBuilder, limit) {
  const tokens = tokenize(query);
  if (!tokens.length) {
    return [];
  }

  return items
    .map((item, index) => ({ item, index, score: scoreText(textBuilder(item), tokens) }))
    .filter((entry) => entry.score > 0)
    .sort((a, b) => b.score - a.score || a.index - b.index)
    .slice(0, limit)
    .map((entry) => entry.item);
}

function shouldExposeTools(context, situations, architectureItems) {
  const entryMode = context.classification?.entryMode || context.entryMode || "";
  const text = normalizeText(context.userText || "");
  if (entryMode === "tool_discovery" || entryMode === "specific_tool_request") {
    return true;
  }

  if (/инструмент|метод|шаблон|фреймворк|матриц|канва|canvas|raci|okr|crm|дашборд/.test(text)) {
    return true;
  }

  return situations.length > 0 && architectureItems.length > 0 && /что делать|как исправ|какой шаг|дальше|решени/.test(text);
}

export function selectBusinessArchitectureGuidance(context = {}, { situationLimit = 3, itemLimit = 5, toolLimit = 4 } = {}) {
  const metaQuestion = isArchitectureMetaQuestion(context);
  const query = [
    context.userText,
    ...(context.history || []).map((message) => message?.text || message?.content || ""),
    ...(context.observations || []).map((item) => typeof item === "string" ? item : JSON.stringify(item)),
    stringifyPacket(context.observationPacket),
    stringifyPacket(context.graphPacket)
  ].join("\n");

  const situations = metaQuestion ? [] : selectTop(
    TYPICAL_BUSINESS_SITUATIONS,
    query,
    (item) => [
      item.group,
      item.situation,
      item.entrepreneurPain,
      item.commonWrongFix,
      item.possibleRootCause,
      item.architectureMove,
      item.diagnosticQuestion,
      item.checkLayers.join(" ")
    ].join(" "),
    situationLimit
  );

  const layerIds = new Set();
  for (const situation of situations) {
    for (const id of situation.checkLayerIds || []) {
      layerIds.add(id);
    }
  }

  const directLayerMatches = selectTop(
    BUSINESS_ARCHITECTURE_LAYERS,
    query,
    (layer) => [layer.name, layer.whatItIs, layer.priorityWhen, layer.meaning, layer.businessSymptoms, layer.diagnosticQuestion].join(" "),
    4
  );
  for (const layer of directLayerMatches) {
    layerIds.add(layer.id);
  }

  const relevantLayerIds = [...layerIds].filter(Boolean);
  const relevantLayers = relevantLayerIds.length
    ? BUSINESS_ARCHITECTURE_LAYERS.filter((layer) => relevantLayerIds.includes(layer.id))
    : BUSINESS_ARCHITECTURE_LAYERS;

  const scopedItems = BUSINESS_ARCHITECTURE_ITEMS.filter((item) =>
    relevantLayerIds.length ? relevantLayerIds.includes(item.layerId) : item.block === "Слой"
  );
  const architectureItems = metaQuestion ? [] : selectTop(
    scopedItems,
    query,
    (item) => [item.layer, item.block, item.domain, item.description, item.action, item.expectedResult, item.toolHints].join(" "),
    itemLimit
  );

  const scopedTools = BUSINESS_ARCHITECTURE_TOOLS.filter((tool) =>
    relevantLayerIds.length ? relevantLayerIds.includes(tool.layerId) : true
  );
  const tools = metaQuestion || !shouldExposeTools(context, situations, architectureItems) ? [] : selectTop(
    scopedTools,
    query,
    (tool) => [tool.layer, tool.domain, tool.name, tool.description, tool.whenToUse, tool.result].join(" "),
    toolLimit
  );

  const maturityEffects = metaQuestion ? [] : BUSINESS_MATURITY_EFFECTS.filter((effect) =>
    relevantLayerIds.includes(effect.layerId)
  ).slice(0, 6);

  return {
    layerClasses: BUSINESS_ARCHITECTURE_LAYER_CLASSES,
    layerMap: BUSINESS_ARCHITECTURE_LAYERS,
    relevantLayers,
    situations,
    architectureItems,
    tools,
    maturityEffects,
    relevantLayerNames: layerNamesForIds(relevantLayerIds),
    metaQuestion
  };
}

export function renderBusinessArchitectureMapForPrompt() {
  const classes = BUSINESS_ARCHITECTURE_LAYER_CLASSES
    .map((item) => `${item.classId} — ${item.name}: ${item.description}`)
    .join("\n");

  const layers = BUSINESS_ARCHITECTURE_LAYERS
    .map((item) => [
      `${item.classId}. ${item.name}`,
      `- Что это: ${item.whatItIs}`,
      `- Роль: ${item.systemRole}`,
      `- Приоритет, когда: ${item.priorityWhen}`,
      `- Тип ограничения: ${item.constraintType}`,
      `- Смысл: ${item.meaning}`,
      `- Проявления: ${item.businessSymptoms}`,
      `- Диагностический вопрос: ${item.diagnosticQuestion}`
    ].join("\n"))
    .join("\n\n");

  return `Классы причинной карты:\n${classes}\n\n11 бизнес-слоёв:\n${layers}`;
}

export function renderBusinessArchitectureGuidanceForPrompt(context = {}) {
  const guidance = selectBusinessArchitectureGuidance(context);

  if (guidance.metaQuestion) {
    return [
      "Контекстные ориентиры из бизнес-архитектуры:",
      "Пользователь спрашивает про метод или карту анализа. Не подбирай типовые ситуации и инструменты.",
      "Ответь прямо: основная карта = 11 бизнес-слоёв, сгруппированных в классы A-D; классы A-D не задают линейный порядок обхода, а помогают держать разные классы объяснений."
    ].join("\n");
  }

  const situations = guidance.situations.map((item) => [
    `- ${compactText(item.group, 80)}: ${compactText(item.entrepreneurPain, 160)}`,
    `  Ситуация: ${compactText(item.situation, 220)}`,
    `  Частая ложная реакция: ${compactText(item.commonWrongFix, 180)}`,
    `  Возможный корень: ${compactText(item.possibleRootCause, 260)}`,
    `  Проверить слои: ${item.checkLayers.join(", ")}`,
    `  Сильный вопрос: ${compactText(item.diagnosticQuestion, 220)}`
  ].join("\n")).join("\n");

  const architectureItems = guidance.architectureItems.map((item) => [
    `- ${compactText(item.layer, 80)} / ${compactText(item.domain, 120)} (${item.block})`,
    `  Смысл: ${compactText(item.description, 260)}`,
    `  Действие: ${compactText(item.action, 220)}`,
    `  Результат: ${compactText(item.expectedResult, 220)}`
  ].join("\n")).join("\n");

  const tools = guidance.tools.map((tool) => [
    `- ${compactText(tool.layer, 80)} / ${compactText(tool.domain, 120)}: ${compactText(tool.name, 160)}`,
    `  Что это: ${compactText(tool.description, 240)}`,
    `  Когда применять: ${compactText(tool.whenToUse, 220)}`,
    `  Результат: ${compactText(tool.result, 220)}`
  ].join("\n")).join("\n");

  const maturity = guidance.maturityEffects.map((item) =>
    `- ${item.layer} ${item.transition}: ${compactText(item.moneyEffect, 160)}. Было: ${compactText(item.before, 180)}. Стало: ${compactText(item.after, 180)}`
  ).join("\n");

  return [
    "Контекстные ориентиры из бизнес-архитектуры:",
    guidance.relevantLayerNames.length ? `Вероятные слои проверки: ${guidance.relevantLayerNames.join(", ")}` : "Вероятные слои проверки: пока не сужены.",
    situations ? `\nПохожие типовые ситуации:\n${situations}` : "",
    architectureItems ? `\nРелевантные домены/поддомены:\n${architectureItems}` : "",
    tools ? `\nВозможные инструменты как ориентиры, не как готовая рекомендация:\n${tools}` : "",
    maturity ? `\nЭффекты зрелости, если нужно объяснить ценность движения:\n${maturity}` : ""
  ].filter(Boolean).join("\n");
}
